1	/**
2	 * judge-panel.ts — 3-model LLM judge panel for soul file change evaluation.
3	 *
4	 * Calls Gemini, MiniMax, and Grok in parallel. Unanimous approval required.
5	 * API failures and parse failures both count as rejections (conservative default).
6	 *
7	 * Does NOT apply or stage changes — that is the orchestration layer's responsibility.
8	 * Does NOT read soul files from disk — receives content as input.
9	 * Does NOT write to brain.db or the filesystem.
10	 */
11	
12	import { generateText as geminiGenerate } from "./gemini.js";
13	import { chatCompletion as minimaxChat } from "./minimax.js";
14	import { chatCompletion as grokChat } from "./grok.js";
15	import type { AllGatesResult } from "./gates.js";
16	
17	// ── Types ─────────────────────────────────────────────────────────────────────
18	
19	export type JudgeVote = "approve" | "reject";
20	
21	export interface JudgeVerdict {
22	  model: string;        // "gemini" | "minimax" | "grok"
23	  vote: JudgeVote;
24	  reason: string;       // explanation for the vote
25	  latencyMs: number;    // how long this judge took
26	}
27	
28	export interface JudgePanelResult {
29	  approved: boolean;    // true only if ALL judges voted approve
30	  votes: JudgeVerdict[];
31	  unanimous: boolean;   // same as approved (all must agree)
32	  dissents: string[];   // model names that voted reject
33	}
34	
35	export interface JudgePanelInput {
36	  agent: string;
37	  currentSoul: string;       // full text of current soul file
38	  proposedDiff: string;      // human-readable diff description
39	  evidence: string;          // knowledge file excerpts supporting the change
40	  gateResults: AllGatesResult;
41	}
42	
43	// ── Prompt Builder ────────────────────────────────────────────────────────────
44	
45	/**
46	 * Build the judge prompt. Same content is sent to all three models (fairness).
47	 */
48	export function buildJudgePrompt(input: JudgePanelInput): string {
49	  const gateLines = input.gateResults.results
50	    .map(r => `- ${r.gate}: ${r.pass ? "PASS" : "FAIL"} — ${r.reason}`)
51	    .join("\n");
52	
53	  return `You are a judge reviewing a proposed change to an AI agent's soul file (core identity document).
54	
55	## Agent: ${input.agent}
56	
57	## Current Soul File
58	${input.currentSoul}
59	
60	## Proposed Change
61	${input.proposedDiff}
62	
63	## Evidence (from knowledge files)
64	${input.evidence}
65	
66	## Validation Gate Results
67	All structural gates passed:
68	${gateLines}
69	
70	## Your Task
71	
72	Evaluate whether this soul file change should be automatically applied. Consider:
73	
74	1. **Evidence quality:** Is the change supported by sufficient evidence from multiple sessions/workflows? A single observation is not enough for a soul change.
75	2. **Non-contradiction:** Does this change coexist with existing soul traits? (The regression gate checked embedding similarity, but you should check semantic compatibility at a deeper level.)
76	3. **Utility:** Will this change genuinely improve the agent's future work? Or is it trivial, situational, or already implied by existing traits?
77	4. **Proportionality:** Is the magnitude of the change proportional to the evidence? Small, proven refinements are good. Large shifts need overwhelming evidence.
78	
79	## Response Format
80	
81	Respond with EXACTLY one line in this format:
82	APPROVE: {brief reason why this change is safe and beneficial}
83	or
84	REJECT: {brief reason why this change should not be auto-applied}
85	
86	Do not include any other text.`;
87	}
88	
89	// ── Response Parser ───────────────────────────────────────────────────────────
90	
91	/**
92	 * Parse a judge's raw text response into a structured verdict.
93	 * Conservative: anything that doesn't start with APPROVE is a rejection.
94	 * An unparseable response is a rejection — we never let confusion approve a change.
95	 */
96	export function parseVerdict(model: string, text: string, latencyMs: number): JudgeVerdict {
97	  const trimmed = text.trim();
98	
99	  if (trimmed.toUpperCase().startsWith("APPROVE")) {
100	    const reason = trimmed.replace(/^APPROVE:?\s*/i, "").trim() || "Approved without specific reason";
101	    return { model, vote: "approve", reason, latencyMs };
102	  }
103	
104	  if (trimmed.toUpperCase().startsWith("REJECT")) {
105	    const reason = trimmed.replace(/^REJECT:?\s*/i, "").trim() || "Rejected without specific reason";
106	    return { model, vote: "reject", reason, latencyMs };
107	  }
108	
109	  // Fallback: unparseable response = reject (conservative)
110	  return {
111	    model,
112	    vote: "reject",
113	    reason: `Could not parse judge response. Raw: "${trimmed.slice(0, 200)}"`,
114	    latencyMs,
115	  };
116	}
117	
118	// ── Individual Judge Calls ────────────────────────────────────────────────────
119	
120	// MiniMax M2.5 burns ~100-150 tokens on internal reasoning before producing visible text.
121	// 256 tokens hits the limit during reasoning and returns empty responses. 1024 leaves
122	// comfortable headroom. Gemini and Grok bumped to the same for consistency.
123	const JUDGE_MAX_TOKENS = 1024;
124	
125	async function callGeminiJudge(prompt: string): Promise<JudgeVerdict> {
126	  const start = Date.now();
127	  const result = await geminiGenerate(prompt, {
128	    model: "gemini-2.5-flash",
129	    temperature: 0.2,
130	    maxOutputTokens: JUDGE_MAX_TOKENS,
131	    caller: "judge-panel-gemini",
132	  });
133	  return parseVerdict("gemini", result.text, Date.now() - start);
134	}
135	
136	async function callMinimaxJudge(prompt: string): Promise<JudgeVerdict> {
137	  const start = Date.now();
138	  const result = await minimaxChat({
139	    model: "MiniMax-M2.5",
140	    messages: [{ role: "user", content: prompt }],
141	    temperature: 0.2,
142	    maxTokens: JUDGE_MAX_TOKENS,
143	    caller: "judge-panel-minimax",
144	  });
145	  return parseVerdict("minimax", result.text, Date.now() - start);
146	}
147	
148	async function callGrokJudge(prompt: string): Promise<JudgeVerdict> {
149	  const start = Date.now();
150	  const result = await grokChat({
151	    model: "grok-4-1-fast-non-reasoning",
152	    messages: [{ role: "user", content: prompt }],
153	    temperature: 0.2,
154	    maxTokens: JUDGE_MAX_TOKENS,
155	    caller: "judge-panel-grok",
156	  });
157	  return parseVerdict("grok", result.text, Date.now() - start);
158	}
159	
160	// ── Main Panel Function ───────────────────────────────────────────────────────
161	
162	/**
163	 * Run the 3-model judge panel.
164	 *
165	 * All three models are called in parallel via Promise.allSettled.
166	 * API failures (timeout, 429, network error) count as rejections — infrastructure
167	 * failures must not enable auto-application of soul changes.
168	 *
169	 * Unanimous approval required: one rejection stages the change for human review.
170	 *
171	 * @param input - The soul change to evaluate
172	 * @returns Panel result with all votes and aggregated verdict
173	 */
174	export async function runJudgePanel(input: JudgePanelInput): Promise<JudgePanelResult> {
175	  const prompt = buildJudgePrompt(input);
176	
177	  const results = await Promise.allSettled([
178	    callGeminiJudge(prompt),
179	    callMinimaxJudge(prompt),
180	    callGrokJudge(prompt),
181	  ]);
182	
183	  const modelNames = ["gemini", "minimax", "grok"] as const;
184	
185	  const votes: JudgeVerdict[] = results.map((result, i) => {
186	    if (result.status === "fulfilled") {
187	      return result.value;
188	    }
189	    // API failure = reject (conservative)
190	    const errorMsg = (result.reason as Error)?.message ?? "unknown error";
191	    return {
192	      model: modelNames[i],
193	      vote: "reject" as JudgeVote,
194	      reason: `API error: ${errorMsg}`,
195	      latencyMs: 0,
196	    };
197	  });
198	
199	  const dissents = votes.filter(v => v.vote === "reject").map(v => v.model);
200	  const approved = dissents.length === 0;
201	
202	  return {
203	    approved,
204	    votes,
205	    unanimous: approved,
206	    dissents,
207	  };
208	}
