249	
250	  // Extract summary
251	  const summaryMatch = output.match(/SUMMARY:\n([\s\S]*?)(?=\nPROPOSALS:)/);
252	  if (summaryMatch) {
253	    out.push("");
254	    out.push("--- SUMMARY ---");
255	    out.push(summaryMatch[1].trim());
256	    out.push("--- END SUMMARY ---");
257	  }
258	
259	  // Extract proposals
260	  const proposalRegex = /===\s*PROPOSAL\s*\d+:\s*(.*?)\s*===\n([\s\S]*?)===\s*END PROPOSAL\s*===/g;
261	  const proposals: { title: string; body: string }[] = [];
