265	  }
266	
267	  if (proposals.length > 0) {
268	    out.push("");
269	    out.push(`${proposals.length} proposal(s):`);
270	    out.push("");
271	    for (let i = 0; i < proposals.length; i++) {
272	      out.push(`  ${i + 1}. ${proposals[i].title}`);
