274	      const lines = proposals[i].body.split("\n");
275	      for (const line of lines.slice(0, 6)) {
276	        out.push(`     ${line}`);
277	      }
278	      if (lines.length > 6) out.push(`     ... (${lines.length - 6} more lines)`);
279	      out.push("");
280	    }
281	  }
282	
283	  // Extract full soul
284	  const fullSoulMatch = output.match(/FULL_SOUL:\n([\s\S]*?)$/);
