294	    out.push(`  bun src/tools/distill-soul.ts --agent ${agent} --apply`);
295	    out.push("");
296	
297	    if (newSoulContent) {
298	      out.push("--- PROPOSED SOUL FILE ---");
299	      out.push(newSoulContent);
300	      out.push("--- END ---");
301	    }
302	
303	    return out.join("\n");
304	  }
305	
306	  // Apply mode
307	  if (!newSoulContent) {
308	    throw new Error("Could not extract the full soul content from Gemini output. Run with --dry-run to see the raw output.");
309	  }
310	
311	  writeFileSync(soulPath, newSoulContent + "\n", "utf-8");
312	  out.push("");
313	  out.push(`Soul file updated: ${soulPath}`);
314	  out.push(`${proposals.length} proposal(s) applied.`);
315	  out.push("");
316	  out.push("=== DISTILLATION COMPLETE ===");
317	
318	  return out.join("\n");
319	}
320	
321	// ── Tool definition ────────────────────────────────────────────────────────
322	
323	export const toolDef: ToolDefinition = {
324	  name: "distill_soul",
325	  description: "Propose soul file updates from accumulated knowledge. Compares an agent's knowledge files against their soul file, identifies proven learnings, and proposes changes. Default is dry-run (proposal only).",
326	  inputSchema: z.object({
327	    agent: z.string().describe("Agent name (tala, rune, sol, echo, penny)"),
328	    apply: z.boolean().optional().describe("Write approved changes to soul file (default: false / dry-run)"),
329	  }),
330	  tags: ["memory"],
331	  execute: async (args) => {
332	    try {
333	      const result = await distillSoul(args.agent, args.apply ?? false);
334	      return { output: result };
335	    } catch (err: any) {
336	      return { output: `[distill_soul error] ${err.message}`, isError: true };
337	    }
338	  },
339	};
340	
341	// ── CLI mode ───────────────────────────────────────────────────────────────
342	
343	if (import.meta.main) {
344	  let agent = "";
345	  let apply = false;
346	
347	  const args = process.argv.slice(2);
348	  for (let i = 0; i < args.length; i++) {
349	    if (args[i] === "--agent") agent = args[++i];
350	    else if (args[i] === "--apply") apply = true;
351	    else if (args[i] === "--dry-run") apply = false;
352	  }
353	
354	  if (!agent || !AGENTS.includes(agent)) {
355	    console.log("Usage: bun src/tools/distill-soul.ts --agent {agent} [--apply]");
356	    console.log(`Agents: ${AGENTS.join(", ")}`);
357	    console.log("\nDefault is --dry-run (show proposal only).");
358	    process.exit(1);
359	  }
360	
361	  try {
362	    const result = await distillSoul(agent, apply);
363	    console.log(result);
364	  } catch (err: any) {
365	    console.error(err.message);
366	    process.exit(1);
367	  }
368	}
