#!/usr/bin/env bun
/**
 * distill-soul.ts — Propose soul file updates from accumulated knowledge
 *
 * Dual-mode: CLI (`bun src/tools/distill-soul.ts --agent tala`) or native tool via registry.
 *
 * Reads an agent's knowledge/ files and current soul file, identifies
 * proven and fundamental learnings, and proposes a diff. User approves
 * before anything is written to the soul.
 *
 * Usage:
 *   bun src/tools/distill-soul.ts --agent tala
 *   bun src/tools/distill-soul.ts --agent tala --dry-run
 *   bun src/tools/distill-soul.ts --agent tala --apply
 *
 * Options:
 *   --agent    Agent name (tala, rune, sol, echo, penny)
 *   --dry-run  Show proposal without writing (default)
 *   --apply    Write approved changes to soul file
 */

import { existsSync, readFileSync, readdirSync, writeFileSync } from "fs";
import { join } from "path";
import { generateText } from "../libs/gemini.js";
import { fromRoot } from "../libs/paths.js";
import { z } from "zod";
import type { ToolDefinition } from "../registry/types.js";

// ── Paths ───────────────────────────────────────────────────────────────────

const memoryRoot = fromRoot("vault", "studio", "memory");
const soulsDir = fromRoot(".claude", "souls");

const AGENTS = ["tala", "rune", "sol", "echo", "penny"];

// ── Helpers ─────────────────────────────────────────────────────────────────

function loadDir(dir: string): string {
  if (!existsSync(dir)) return "";
  const files = readdirSync(dir).filter(f => f.endsWith(".md"));
  if (files.length === 0) return "";
  return files
    .map(f => `### ${f}\n${readFileSync(join(dir, f), "utf-8")}`)
    .join("\n\n");
}

// ── Raw Gemini result type ──────────────────────────────────────────────────

export interface RawDistillResult {
  /** Raw Gemini text with === PROPOSAL === markers — use for programmatic parsing */
  rawOutput: string;
  /** True if Gemini returned NO_CHANGES or there was nothing to distill */
  noChanges: boolean;
  /** Human-readable reason when noChanges is true */
  skipReason?: string;
  inputTokens?: number;
  outputTokens?: number;
}

// ── Raw Gemini call (exported for autonomous-distill pipeline) ──────────────

/**
 * Build prompt, call Gemini, and return the raw output for programmatic parsing.
 * Does NOT parse or format — callers receive the raw text with === PROPOSAL === markers.
 *
 * Throws on invalid agent, missing soul file, or Gemini failure.
 * Returns noChanges:true for empty knowledge or Gemini NO_CHANGES response.
 */
export async function callDistillGemini(agent: string): Promise<RawDistillResult> {
  if (!AGENTS.includes(agent)) {
    throw new Error(`Invalid agent: ${agent}. Must be one of: ${AGENTS.join(", ")}`);
  }

  const soulPath = join(soulsDir, `${agent}.md`);
  if (!existsSync(soulPath)) {
    throw new Error(`Soul file not found: ${soulPath}`);
  }

  const soulContent = readFileSync(soulPath, "utf-8");

  const knowledgeDir = join(memoryRoot, agent, "knowledge");
  const sharedKnowledgeDir = join(memoryRoot, "shared", "knowledge");

  const agentKnowledge = loadDir(knowledgeDir);
  const sharedKnowledge = loadDir(sharedKnowledgeDir);

  if (!agentKnowledge && !sharedKnowledge) {
    return {
      rawOutput: "",
      noChanges: true,
      skipReason: "No knowledge files found",
    };
  }

  // ── Distillation prompt ─────────────────────────────────────────────────

  const prompt = `You are a soul distillation engine. Your job is to evolve an AI agent's core identity file based on proven knowledge.

## The Distinction

**Soul file** = the agent's brain. Core identity, permanent beliefs, proven techniques. What makes this agent *this agent*. Written in the agent's voice.

**Knowledge files** = the agent's notebook. Verified learnings, platform quirks, techniques. Can be wrong, outdated, or situational.

A learning graduates from knowledge → soul when it is:
- **Proven:** Appeared in 2+ workflows or confirmed by multiple observations
- **Fundamental:** Changes how the agent approaches work, not just a one-off tip
- **Durable:** Won't become stale next week (unless it's a deep platform truth)
- **Identity-shaping:** Reflects who the agent IS, not just what it knows

## Current Soul File
\`\`\`markdown
${soulContent}
\`\`\`

## Agent Knowledge
${agentKnowledge || "(no agent-specific knowledge)"}

## Shared Knowledge
${sharedKnowledge || "(no shared knowledge)"}

## Task

1. Read the soul file carefully — understand the agent's voice, structure, and existing beliefs
2. Read all knowledge files — identify learnings that meet the graduation criteria
3. Propose changes to the soul file

## Output Format

If nothing qualifies for soul promotion, respond with exactly: NO_CHANGES

Otherwise, respond with this structure:

SUMMARY:
(2-3 sentences: what's changing and why)

PROPOSALS:
Each proposal is a discrete change. For each:

=== PROPOSAL N: {short title} ===
TYPE: add | modify | remove
SECTION: {which soul file section this belongs in}
CONFIDENCE: high | medium
EVIDENCE: {brief — what knowledge entries support this}

CONTENT:
{The exact text to add to the soul file (max 6 lines), written in the agent's voice}
=== END PROPOSAL ===

FULL_SOUL:
{The complete updated soul file with all proposals applied. This is what would be written if approved.}

## Rules

- Write in the agent's voice, not yours
- Don't add sections that don't fit the soul's existing structure
- Don't repeat what's already in the soul (check carefully)
- Don't add evidence trails, timestamps, or metadata — soul is timeless
- Prefer modifying existing sections over adding new ones
- If a learning contradicts something in the soul, the newer proven learning wins
- Be conservative — when in doubt, leave it in knowledge
- **CONTENT size: max 6 lines per proposal (hard limit).** Prefer a single bullet point or short paragraph. If a learning requires more than 6 lines to express, split it into multiple smaller proposals.
- **No full section rewrites.** Propose surgical refinements, not replacements. CONTENT should be what you are ADDING to a section (even for modify-type proposals — the auto-apply system appends, never replaces).
- 1-3 proposals is typical. More than 5 means you're not being selective enough`;

  // ── Run Gemini ──────────────────────────────────────────────────────────

  let rawOutput: string;
  let inputTokens: number | undefined;
  let outputTokens: number | undefined;

  try {
    const result = await generateText(prompt, {
      model: "gemini-2.5-flash",
      timeout: 120_000,
      maxOutputTokens: 16384,
      temperature: 0.3,
      caller: "distill-soul",
    });
    rawOutput = result.text;
    inputTokens = result.inputTokens;
    outputTokens = result.outputTokens;
  } catch (err: any) {
    throw new Error(`Gemini failed: ${err.message?.split("\n")[0] || "unknown"}`);
  }

  if (rawOutput.includes("NO_CHANGES")) {
    return {
      rawOutput,
      noChanges: true,
      skipReason: "No knowledge qualifies for soul promotion",
      inputTokens,
      outputTokens,
    };
  }

  return { rawOutput, noChanges: false, inputTokens, outputTokens };
}

// ── Core function ───────────────────────────────────────────────────────────

async function distillSoul(agent: string, apply: boolean): Promise<string> {
  const out: string[] = [];

  const soulPath = join(soulsDir, `${agent}.md`);

  // Resolve knowledge presence for header (callDistillGemini validates agent/soul)
  const knowledgeDir = join(memoryRoot, agent, "knowledge");
  const sharedKnowledgeDir = join(memoryRoot, "shared", "knowledge");
  const agentKnowledge = existsSync(knowledgeDir)
    ? readdirSync(knowledgeDir).filter(f => f.endsWith(".md")).length > 0
    : false;
  const sharedKnowledge = existsSync(sharedKnowledgeDir)
    ? readdirSync(sharedKnowledgeDir).filter(f => f.endsWith(".md")).length > 0
    : false;

  out.push(`=== SOUL DISTILLATION: ${agent} ===`);
  out.push(`  Soul: ${soulPath}`);
  out.push(`  Knowledge: ${agentKnowledge ? "yes" : "none"} (agent), ${sharedKnowledge ? "yes" : "none"} (shared)`);
  out.push("");
  out.push("Analyzing knowledge against soul...");

  let rawResult: RawDistillResult;
  try {
    rawResult = await callDistillGemini(agent);
  } catch (err: any) {
    throw err;
  }

  if (rawResult.inputTokens || rawResult.outputTokens) {
    out.push(`  Gemini: ${rawResult.inputTokens ?? "?"} in / ${rawResult.outputTokens ?? "?"} out tokens`);
  }

  if (rawResult.noChanges) {
    out.push("");
    if (rawResult.skipReason === "No knowledge files found") {
      out.push(`No knowledge files found for "${agent}". Nothing to distill.`);
      out.push("Run some workflows and let the reflection engine build up knowledge first.");
    } else {
      out.push("No knowledge qualifies for soul promotion yet.");
      out.push("Keep running workflows — learnings need to be proven before they enter the soul.");
    }
    return out.join("\n");
  }

  const output = rawResult.rawOutput;

  // ── Parse output ────────────────────────────────────────────────────────

  // Extract summary
  const summaryMatch = output.match(/SUMMARY:\n([\s\S]*?)(?=\nPROPOSALS:)/);
  if (summaryMatch) {
    out.push("");
    out.push("--- SUMMARY ---");
    out.push(summaryMatch[1].trim());
    out.push("--- END SUMMARY ---");
  }

  // Extract proposals
  const proposalRegex = /===\s*PROPOSAL\s*\d+:\s*(.*?)\s*===\n([\s\S]*?)===\s*END PROPOSAL\s*===/g;
  const proposals: { title: string; body: string }[] = [];
  let match;
  while ((match = proposalRegex.exec(output)) !== null) {
    proposals.push({ title: match[1].trim(), body: match[2].trim() });
  }

  if (proposals.length > 0) {
    out.push("");
    out.push(`${proposals.length} proposal(s):`);
    out.push("");
    for (let i = 0; i < proposals.length; i++) {
      out.push(`  ${i + 1}. ${proposals[i].title}`);
      // Show first few lines of each proposal
      const lines = proposals[i].body.split("\n");
      for (const line of lines.slice(0, 6)) {
        out.push(`     ${line}`);
      }
      if (lines.length > 6) out.push(`     ... (${lines.length - 6} more lines)`);
      out.push("");
    }
  }

  // Extract full soul
  const fullSoulMatch = output.match(/FULL_SOUL:\n([\s\S]*?)$/);
  const newSoulContent = fullSoulMatch
    ? fullSoulMatch[1].replace(/^```markdown?\n?/, "").replace(/```\s*$/, "").trim()
    : null;

  // ── Apply or dry-run ────────────────────────────────────────────────────

  if (!apply) {
    out.push("--- MODE: DRY RUN ---");
    out.push("Review the proposals above. To apply:");
    out.push(`  bun src/tools/distill-soul.ts --agent ${agent} --apply`);
    out.push("");

    if (newSoulContent) {
      out.push("--- PROPOSED SOUL FILE ---");
      out.push(newSoulContent);
      out.push("--- END ---");
    }

    return out.join("\n");
  }

  // Apply mode
  if (!newSoulContent) {
    throw new Error("Could not extract the full soul content from Gemini output. Run with --dry-run to see the raw output.");
  }

  writeFileSync(soulPath, newSoulContent + "\n", "utf-8");
  out.push("");
  out.push(`Soul file updated: ${soulPath}`);
  out.push(`${proposals.length} proposal(s) applied.`);
  out.push("");
  out.push("=== DISTILLATION COMPLETE ===");

  return out.join("\n");
}

// ── Tool definition ────────────────────────────────────────────────────────

export const toolDef: ToolDefinition = {
  name: "distill_soul",
  description: "Propose soul file updates from accumulated knowledge. Compares an agent's knowledge files against their soul file, identifies proven learnings, and proposes changes. Default is dry-run (proposal only).",
  inputSchema: z.object({
    agent: z.string().describe("Agent name (tala, rune, sol, echo, penny)"),
    apply: z.boolean().optional().describe("Write approved changes to soul file (default: false / dry-run)"),
  }),
  tags: ["memory"],
  execute: async (args) => {
    try {
      const result = await distillSoul(args.agent, args.apply ?? false);
      return { output: result };
    } catch (err: any) {
      return { output: `[distill_soul error] ${err.message}`, isError: true };
    }
  },
};

// ── CLI mode ───────────────────────────────────────────────────────────────

if (import.meta.main) {
  let agent = "";
  let apply = false;

  const args = process.argv.slice(2);
  for (let i = 0; i < args.length; i++) {
    if (args[i] === "--agent") agent = args[++i];
    else if (args[i] === "--apply") apply = true;
    else if (args[i] === "--dry-run") apply = false;
  }

  if (!agent || !AGENTS.includes(agent)) {
    console.log("Usage: bun src/tools/distill-soul.ts --agent {agent} [--apply]");
    console.log(`Agents: ${AGENTS.join(", ")}`);
    console.log("\nDefault is --dry-run (show proposal only).");
    process.exit(1);
  }

  try {
    const result = await distillSoul(agent, apply);
    console.log(result);
  } catch (err: any) {
    console.error(err.message);
    process.exit(1);
  }
}

