  // Parse frontmatter — simple regex, no YAML dependency
  const fmMatch = rawContent.match(/^---\r?\n([\s\S]*?)\r?\n---/);
  const fm: Record<string, string> = {};
  if (fmMatch) {
    for (const line of fmMatch[1].split(/\r?\n/)) {
      const colonIdx = line.indexOf(":");
      if (colonIdx < 0) continue;
      const key = line.slice(0, colonIdx).trim();
      let val = line.slice(colonIdx + 1).trim();
      if ((val.startsWith('"') && val.endsWith('"')) || (val.startsWith("'") && val.endsWith("'"))) {
        val = val.slice(1, -1);
      }
      if (key) fm[key] = val;
    }
  }

  // Extract proposed change section body
  const changeMatch = rawContent.match(/## Proposed Change\r?\n\r?\n([\s\S]*?)(?=\r?\n## |\s*$)/);
  const proposedChange = changeMatch ? changeMatch[1].trim() : "";

  // Extract reason from frontmatter (preferred) or ## Reason for Staging section
  const reasonFm = fm.reason ?? "";
  const reasonSectionMatch = rawContent.match(/## Reason for Staging\r?\n\r?\n([\s\S]*?)(?=\r?\n## |\s*$)/);
  const reason = reasonFm || (reasonSectionMatch ? reasonSectionMatch[1].trim() : "");

  const section = fm.section ?? "";
  const changeType = fm.change_type ?? "modify";
  const status = fm.status ?? "pending";
  const createdAt = fm.created ?? now();
  const ts = now();

  raw.exec(`
    INSERT INTO staged_proposals (
      agent, section, change_type, proposed_change, reason,
      status, source_path, file_hash, created_at, updated_at
    )
    VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?)
    ON CONFLICT(source_path) DO UPDATE SET
      agent=excluded.agent, section=excluded.section,
      change_type=excluded.change_type, proposed_change=excluded.proposed_change,
      reason=excluded.reason, status=excluded.status,
      file_hash=excluded.file_hash, updated_at=excluded.updated_at
  `.trim(), [agent, section, changeType, proposedChange, reason, status, sourcePath, hash, createdAt, ts] as any);

  // Upsert sync meta
  raw.exec(`
    INSERT INTO sync_meta (source_path, file_hash, table_name, synced_at)
    VALUES (?, ?, 'staged_proposals', ?)
    ON CONFLICT(source_path) DO UPDATE SET
      file_hash=excluded.file_hash, synced_at=excluded.synced_at
  `.trim(), [sourcePath, hash, ts] as any);

  changed++;
}

