1	/**
2	 * gates.ts — Validation gates for soul file changes
3	 *
4	 * 5 gates run in order (cheapest first):
5	 *   1. safety    — deterministic: block changes to protected sections
6	 *   2. size      — deterministic: max 6 added/modified lines, 1 removed
7	 *   3. drift     — deterministic: DB query, cumulative 30-day change limit
8	 *   4. regression — embeddings + optional Gemini: contradiction detection
9	 *   5. constitution — Gemini LLM call: identity alignment check
10	 *
11	 * All 5 gates always run (no short-circuit) — full results for human review.
12	 */
13	
14	import { generateText } from "./gemini.js";
15	import { embedText, embedBatch } from "./embeddings.js";
16	import { querySoulDrift } from "./brain/queries.js";
17	
18	// ── Types ────────────────────────────────────────────────────────────────────
19	
20	export interface GateResult {
21	  gate: string;   // "constitution" | "regression" | "size" | "drift" | "safety"
22	  pass: boolean;
23	  reason: string;
24	}
25	
26	export interface GateInput {
27	  agent: string;
28	  currentSoul: string;
29	  proposedDiff: ProposedChange[];
30	}
31	
32	export interface ProposedChange {
33	  type: "add" | "remove" | "modify";
34	  section: string;
35	  content: string;
36	  evidence: string;
37	}
38	
39	export interface AllGatesResult {
40	  passed: boolean;
41	  results: GateResult[];
42	  failedGates: string[];
43	}
44	
45	// ── Protected section names (case-insensitive) ──────────────────────────────
46	
47	const PROTECTED_SECTION_NAMES = [
48	  "who i am",
49	  "who you are",
50	  "creative philosophy",
51	  "hard rules",
52	  "the line i won't cross",
53	  "my line",
54	  "core identity",
55	];
56	
57	// ── Helper: cosine similarity ────────────────────────────────────────────────
58	
59	export function cosineSimilarity(a: number[], b: number[]): number {
60	  if (a.length === 0 || b.length === 0 || a.length !== b.length) return 0;
61	  let dot = 0;
62	  let magA = 0;
63	  let magB = 0;
64	  for (let i = 0; i < a.length; i++) {
65	    dot += a[i] * b[i];
66	    magA += a[i] * a[i];
67	    magB += b[i] * b[i];
68	  }
69	  const denom = Math.sqrt(magA) * Math.sqrt(magB);
70	  return denom === 0 ? 0 : dot / denom;
71	}
72	
73	// ── Helper: parse protected sections from soul text ──────────────────────────
74	
75	/**
76	 * Returns a Set of lowercase section names that are protected.
77	 * Protected = named in PROTECTED_SECTION_NAMES or contains <!-- protected -->.
78	 */
79	function parseProtectedSections(soulText: string): Set<string> {
80	  const protected_ = new Set<string>();
81	  const lines = soulText.split("\n");
82	  let currentSection = "";
83	  let sectionLines: string[] = [];
84	
85	  function flushSection() {
86	    if (!currentSection) return;
87	    const nameLower = currentSection.toLowerCase();
88	    if (PROTECTED_SECTION_NAMES.includes(nameLower)) {
89	      protected_.add(nameLower);
90	    } else if (sectionLines.some(l => l.includes("<!-- protected -->"))) {
91	      protected_.add(nameLower);
92	    }
93	  }
94	
95	  for (const line of lines) {
96	    const headingMatch = line.match(/^#{1,6}\s+(.+)$/);
97	    if (headingMatch) {
98	      flushSection();
99	      currentSection = headingMatch[1].trim();
100	      sectionLines = [];
101	    } else {
102	      sectionLines.push(line);
103	    }
104	  }
105	  flushSection();
106	
107	  return protected_;
108	}
109	
110	// ── Helper: extract rule-like sentences from soul text ──────────────────────
111	
112	/**
113	 * Returns lines that look like rules: list items, lines with modal verbs,
114	 * or lines inside Hard Rules / Core Opinions / Postmortem Reflexes sections.
115	 */
116	function extractRuleSentences(soulText: string): string[] {
117	  const rules: string[] = [];
118	  const lines = soulText.split("\n");
119	  const ruleHeaders = ["hard rules", "core opinions", "postmortem reflexes"];
120	  let inRuleSection = false;
121	
122	  for (const line of lines) {
123	    const trimmed = line.trim();
124	    if (!trimmed) continue;
125	
126	    // Check for section heading
127	    const headingMatch = trimmed.match(/^#{1,6}\s+(.+)$/);
128	    if (headingMatch) {
129	      inRuleSection = ruleHeaders.includes(headingMatch[1].toLowerCase());
130	      continue;
131	    }
132	
133	    // Collect from rule sections unconditionally
134	    if (inRuleSection) {
135	      rules.push(trimmed);
136	      continue;
137	    }
138	
139	    // List items (-, *, numbered)
140	    if (/^[-*]\s+.+/.test(trimmed) || /^\d+\.\s+.+/.test(trimmed)) {
141	      rules.push(trimmed);
142	      continue;
143	    }
144	
145	    // Lines with modal verbs
146	    if (/\b(always|never|must|don't|do not)\b/i.test(trimmed)) {
147	      rules.push(trimmed);
148	      continue;
149	    }
150	  }
151	
152	  return rules;
153	}
154	
155	// ── Gate 1: Safety ───────────────────────────────────────────────────────────
156	
157	/**
158	 * Gate 1 (cheapest): Block any changes targeting protected sections.
159	 * Fully deterministic — no LLM, no DB.
160	 */
161	async function runSafetyGate(input: GateInput): Promise<GateResult> {
162	  if (!input.currentSoul || typeof input.currentSoul !== "string") {
163	    return { gate: "safety", pass: false, reason: "currentSoul is empty or invalid" };
164	  }
165	  if (!input.proposedDiff || input.proposedDiff.length === 0) {
166	    return { gate: "safety", pass: true, reason: "No proposed changes — nothing to check" };
167	  }
168	
169	  const protected_ = parseProtectedSections(input.currentSoul);
170	  if (protected_.size === 0) {
171	    return { gate: "safety", pass: true, reason: "No protected sections found in soul file" };
172	  }
173	
174	  const violations: string[] = [];
175	  for (const change of input.proposedDiff) {
176	    const sectionLower = (change.section ?? "").toLowerCase().trim();
177	    if (protected_.has(sectionLower)) {
178	      violations.push(`"${change.section}" is a protected section`);
179	    }
180	  }
181	
182	  if (violations.length > 0) {
183	    return {
184	      gate: "safety",
185	      pass: false,
186	      reason: `Changes target protected sections: ${violations.join("; ")}`,
187	    };
188	  }
189	
190	  return { gate: "safety", pass: true, reason: "No changes target protected sections" };
191	}
192	
193	// ── Gate 2: Size ─────────────────────────────────────────────────────────────
194	
195	/**
196	 * Gate 2: Enforce per-cycle line budget.
197	 * Max 6 added/modified lines, max 1 removed.
198	 * modify is treated like add — content is appended to the target section (non-destructive).
199	 * Fully deterministic — no LLM, no DB.
200	 */
201	async function runSizeGate(input: GateInput): Promise<GateResult> {
202	  if (!input.proposedDiff || input.proposedDiff.length === 0) {
203	    return { gate: "size", pass: true, reason: "No proposed changes" };
204	  }
205	
206	  const addedLines = input.proposedDiff
207	    .filter(c => c.type === "add" || c.type === "modify")
208	    .reduce((sum, c) => sum + (c.content ? c.content.split("\n").length : 0), 0);
209	
210	  const removedCount = input.proposedDiff.filter(c => c.type === "remove").length;
211	
212	  const failures: string[] = [];
213	  if (addedLines > 6) {
214	    failures.push(`${addedLines} lines added/modified (max 6)`);
215	  }
216	  if (removedCount > 1) {
217	    failures.push(`${removedCount} removals (max 1)`);
218	  }
219	
220	  if (failures.length > 0) {
221	    return { gate: "size", pass: false, reason: failures.join("; ") };
222	  }
223	
224	  return {
225	    gate: "size",
226	    pass: true,
227	    reason: `${addedLines} lines added/modified, ${removedCount} removed — within limits`,
228	  };
229	}
230	
231	// ── Gate 3: Drift ────────────────────────────────────────────────────────────
232	
233	/**
234	 * Gate 3: Block if cumulative 30-day changes exceed 10% of soul file line count.
235	 * Reads soul_changes table via querySoulDrift().
236	 */
237	async function runDriftGate(input: GateInput): Promise<GateResult> {
238	  if (!input.currentSoul || typeof input.currentSoul !== "string") {
239	    return { gate: "drift", pass: false, reason: "currentSoul is empty — cannot compute soul line count" };
240	  }
241	
242	  const soulLineCount = input.currentSoul.split("\n").length;
243	  if (soulLineCount === 0) {
244	    return { gate: "drift", pass: false, reason: "Soul file appears empty" };
245	  }
246	
247	  const threshold = Math.ceil(soulLineCount * 0.1);
248	
249	  let drift: { added: number; removed: number };
250	  try {
251	    drift = querySoulDrift(input.agent, 30);
252	  } catch (err: any) {
253	    // DB not initialized or table missing — allow through (drift is unknown)
254	    return {
255	      gate: "drift",
256	      pass: true,
257	      reason: `Drift query failed (${err.message}) — allowing through`,
258	    };
259	  }
260	
261	  // Add the lines this proposed change would add/remove
262	  const proposedAdded = (input.proposedDiff ?? [])
263	    .filter(c => c.type === "add")
264	    .reduce((sum, c) => sum + (c.content ? c.content.split("\n").length : 0), 0);
265	  const proposedRemoved = (input.proposedDiff ?? []).filter(c => c.type === "remove").length;
266	
267	  const totalAdded = drift.added + proposedAdded;
268	  const totalRemoved = drift.removed + proposedRemoved;
269	  const totalChange = totalAdded + totalRemoved;
270	
271	  if (totalChange > threshold) {
272	    return {
273	      gate: "drift",
274	      pass: false,
275	      reason: `Cumulative 30-day changes (${totalChange} lines) exceed 10% threshold (${threshold} lines) of soul file (${soulLineCount} lines)`,
276	    };
277	  }
278	
279	  return {
280	    gate: "drift",
281	    pass: true,
282	    reason: `30-day drift ${totalChange}/${threshold} (${soulLineCount}-line soul, 10% threshold)`,
283	  };
284	}
285	
286	// ── Gate 4: Regression ───────────────────────────────────────────────────────
287	
288	const REGRESSION_SIMILARITY_THRESHOLD = 0.85;
289	
290	/**
291	 * Gate 4: Detect regressions by embedding proposed changes against existing rules.
292	 * If cosine similarity > 0.85, calls Gemini to confirm contradiction.
293	 */
294	async function runRegressionGate(input: GateInput): Promise<GateResult> {
295	  if (!input.proposedDiff || input.proposedDiff.length === 0) {
296	    return { gate: "regression", pass: true, reason: "No proposed changes" };
297	  }
298	  if (!input.currentSoul || typeof input.currentSoul !== "string") {
299	    return { gate: "regression", pass: false, reason: "currentSoul is empty — cannot extract rules" };
300	  }
301	
302	  const rules = extractRuleSentences(input.currentSoul);
303	  if (rules.length === 0) {
304	    return { gate: "regression", pass: true, reason: "No rule sentences found in soul — skipping regression check" };
305	  }
306	
307	  // Build change texts
308	  const changeParts = input.proposedDiff
309	    .filter(c => c.content?.trim())
310	    .map(c => `[${c.type}] ${c.content.trim()}`);
311	
312	  if (changeParts.length === 0) {
313	    return { gate: "regression", pass: true, reason: "No change content to embed" };
314	  }
315	
316	  // Embed rules and changes
317	  let ruleEmbeddings: (number[] | null)[];
318	  let changeEmbeddings: (number[] | null)[];
319	
320	  try {
321	    const [ruleResult, changeResult] = await Promise.all([
322	      embedBatch(rules, "gate-regression"),
323	      embedBatch(changeParts, "gate-regression"),
324	    ]);
325	    ruleEmbeddings = ruleResult.embeddings;
326	    changeEmbeddings = changeResult.embeddings;
327	  } catch (err: any) {
328	    // Embedding failure is non-fatal — degrade gracefully
329	    return {
330	      gate: "regression",
331	      pass: true,
332	      reason: `Embedding unavailable (${err.message}) — regression check skipped`,
333	    };
334	  }
335	
336	  // Check each change against each rule for high similarity
337	  const contradictions: string[] = [];
338	  for (let ci = 0; ci < changeParts.length; ci++) {
339	    const changeEmb = changeEmbeddings[ci];
340	    if (!changeEmb) continue;
341	
342	    for (let ri = 0; ri < rules.length; ri++) {
343	      const ruleEmb = ruleEmbeddings[ri];
344	      if (!ruleEmb) continue;
345	
346	      const sim = cosineSimilarity(changeEmb, ruleEmb);
347	      if (sim > REGRESSION_SIMILARITY_THRESHOLD) {
348	        // High similarity — ask Gemini to confirm
349	        let isContradiction = false;
350	        try {
351	          const prompt = [
352	            `You are reviewing a proposed soul file change against an existing rule.`,
353	            ``,
354	            `Existing rule: ${rules[ri]}`,
355	            `Proposed change: ${changeParts[ci]}`,
356	            ``,
357	            `Does the proposed change CONTRADICT the existing rule, or is it COMPATIBLE?`,
358	            `Reply with exactly one word: CONTRADICTION or COMPATIBLE`,
359	          ].join("\n");
360	
361	          const result = await generateText(prompt, {
362	            model: "gemini-2.5-flash",
363	            temperature: 0.2,
364	            maxOutputTokens: 256,
365	            caller: "gate-regression",
366	          });
367	
368	          isContradiction = result.text.trim().toUpperCase().startsWith("CONTRADICTION");
369	        } catch {
370	          // Gemini failure — assume contradiction when similarity is very high
371	          isContradiction = sim > 0.92;
372	        }
373	
374	        if (isContradiction) {
375	          contradictions.push(
376	            `Change "${changeParts[ci].slice(0, 60)}..." contradicts rule "${rules[ri].slice(0, 60)}..." (similarity ${sim.toFixed(2)})`
377	          );
378	        }
379	      }
380	    }
381	  }
382	
383	  if (contradictions.length > 0) {
384	    return {
385	      gate: "regression",
386	      pass: false,
387	      reason: contradictions.join("; "),
388	    };
389	  }
390	
391	  return { gate: "regression", pass: true, reason: "No rule contradictions detected" };
392	}
393	
394	// ── Gate 5: Constitution ─────────────────────────────────────────────────────
395	
396	/**
397	 * Gate 5: LLM identity check — does the proposed change contradict agent identity?
