1	#!/usr/bin/env bun
2	/**
3	 * Manual benchmark for AAR-0009. Run with:
4	 *   bun src/libs/__benchmarks__/autonomous-distill.bench.ts [agent]
5	 *
6	 * Scenario 1 — Pre-populated DB (AAR-0009 addendum / AAR-0008 regression guard):
7	 *   Inserts synthetic staged_proposals rows for a fake agent, runs syncStaged's
8	 *   orphan-removal path, asserts no SQLite errors. Guards against the FTS5
9	 *   corruption bug from the AAR-0008 migration rollout.
10	 *
11	 * Scenario 2 — Cache benchmark (hermetic):
12	 *   Freeze/restore pattern ensures the soul file is IDENTICAL for both cold and
13	 *   hot runs, making the cache key stable. Without this, auto-apply on the cold
14	 *   run mutates the soul → different hash → cache miss on hot run → impossible
15	 *   to hit the 30s target.
16	 *
17	 *   1. Snapshot soul bytes + staged dir state.
18	 *   2. Clear distill cache for the agent.
19	 *   3. Cold run → record coldMs.
20	 *   4. Restore soul + clean staged files (in try/finally).
21	 *   5. Hot run → record hotMs.
22	 *   6. Restore + clean again (in try/finally).
23	 *   7. Assert hotMs < 30s, print speedup ratio.
24	 *
25	 * NOTE: calls real Gemini on the cold run — NOT hermetic overall. Run manually
26	 * after changes, not in CI.
27	 */
28	
29	import { existsSync, readFileSync, writeFileSync, readdirSync, rmSync, mkdirSync } from "fs";
30	import { join } from "path";
31	import { autonomousDistill } from "../autonomous-distill.js";
32	import { clearDistillCache, buildCacheKey, readDistillCache } from "../distill-cache.js";
33	import { syncStaged } from "../brain/sync.js";
34	import { initBrain } from "../brain/index.js";
35	import { getRawDb } from "../sqlite.js";
36	import { fromRoot } from "../paths.js";
37	
38	const TARGET_AGENT = process.argv[2] ?? "echo";
39	const TARGET_MS = 30_000;
40	
41	const SOULS_DIR = fromRoot(".claude", "souls");
42	const MEMORY_ROOT = fromRoot("vault", "studio", "memory");
43	
44	// ── Freeze/restore helpers ────────────────────────────────────────────────────
45	
46	/** Snapshot the soul file bytes. Returns null if the file doesn't exist. */
47	function snapshotSoul(agent: string): Buffer | null {
48	  const soulPath = join(SOULS_DIR, `${agent}.md`);
