#!/usr/bin/env bun
/**
 * Manual benchmark for AAR-0009. Run with:
 *   bun src/libs/__benchmarks__/autonomous-distill.bench.ts [agent]
 *
 * Scenario 1 — Pre-populated DB (AAR-0009 addendum / AAR-0008 regression guard):
 *   Inserts synthetic staged_proposals rows for a fake agent, runs syncStaged's
 *   orphan-removal path, asserts no SQLite errors. Guards against the FTS5
 *   corruption bug from the AAR-0008 migration rollout.
 *
 * Scenario 2 — Cache benchmark (hermetic):
 *   Freeze/restore pattern ensures the soul file is IDENTICAL for both cold and
 *   hot runs, making the cache key stable. Without this, auto-apply on the cold
 *   run mutates the soul → different hash → cache miss on hot run → impossible
 *   to hit the 30s target.
 *
 *   1. Snapshot soul bytes + staged dir state.
 *   2. Clear distill cache for the agent.
 *   3. Cold run → record coldMs.
 *   4. Restore soul + clean staged files (in try/finally).
 *   5. Hot run → record hotMs.
 *   6. Restore + clean again (in try/finally).
 *   7. Assert hotMs < 30s, print speedup ratio.
 *
 * NOTE: calls real Gemini on the cold run — NOT hermetic overall. Run manually
 * after changes, not in CI.
 */

import { existsSync, readFileSync, writeFileSync, readdirSync, rmSync, mkdirSync } from "fs";
import { join } from "path";
import { autonomousDistill } from "../autonomous-distill.js";
import { clearDistillCache, buildCacheKey, readDistillCache } from "../distill-cache.js";
import { syncStaged } from "../brain/sync.js";
import { initBrain } from "../brain/index.js";
import { getRawDb } from "../sqlite.js";
import { fromRoot } from "../paths.js";

const TARGET_AGENT = process.argv[2] ?? "echo";
const TARGET_MS = 30_000;

const SOULS_DIR = fromRoot(".claude", "souls");
const MEMORY_ROOT = fromRoot("vault", "studio", "memory");

// ── Freeze/restore helpers ────────────────────────────────────────────────────

/** Snapshot the soul file bytes. Returns null if the file doesn't exist. */
function snapshotSoul(agent: string): Buffer | null {
  const soulPath = join(SOULS_DIR, `${agent}.md`);
  if (!existsSync(soulPath)) return null;
  return readFileSync(soulPath);
}

/** Restore soul file from a snapshot buffer. No-op if snapshot is null. */
function restoreSoul(agent: string, snapshot: Buffer | null): void {
  if (snapshot === null) return;
  const soulPath = join(SOULS_DIR, `${agent}.md`);
  writeFileSync(soulPath, snapshot);
}

/**
 * Record all .md file paths currently in vault/studio/memory/{agent}/staged/.
 * Returns a Set of absolute paths (empty if the dir doesn't exist).
 */
function snapshotStagedDir(agent: string): Set<string> {
  const stagedDir = join(MEMORY_ROOT, agent, "staged");
  const snapshot = new Set<string>();
  if (!existsSync(stagedDir)) return snapshot;
  for (const f of readdirSync(stagedDir)) {
    if (f.endsWith(".md")) {
      snapshot.add(join(stagedDir, f));
    }
  }
  return snapshot;
}

/**
 * Delete any .md files in vault/studio/memory/{agent}/staged/ that were NOT in
 * the pre-run snapshot. Also runs syncStaged() so brain.db stays consistent.
 * Returns the count of files deleted.
 */
async function cleanStagedDir(agent: string, preSnapshot: Set<string>): Promise<number> {
  const stagedDir = join(MEMORY_ROOT, agent, "staged");
  if (!existsSync(stagedDir)) return 0;
  let deleted = 0;
  for (const f of readdirSync(stagedDir)) {
    if (!f.endsWith(".md")) continue;
    const fullPath = join(stagedDir, f);
    if (!preSnapshot.has(fullPath)) {
      try {
        rmSync(fullPath);
        deleted++;
      } catch {
        // Best effort — don't crash the benchmark on cleanup failure
      }
    }
  }
  // Sync brain.db so it reflects the deletion
  try {
    await syncStaged();
  } catch {
    // Non-fatal — sync failure doesn't affect timing results
  }
  return deleted;
}

// ── Scenario 1: Pre-populated DB ─────────────────────────────────────────────

const PREPOP_AGENT = "__bench_prepop__";

console.log(`[bench] === Scenario 1: Pre-populated DB ===`);
console.log(`[bench] initialising brain.db...`);

let prepopPassed = false;
let prepopError: string | null = null;

try {
  initBrain();
  const raw = getRawDb();

  const now = new Date().toISOString();
  const fakeRows = [
    {
      sourcePath: `vault/studio/memory/${PREPOP_AGENT}/staged/fake-20260407-000001-bench.md`,
      title: "Bench prepop proposal 1",
      section: "Hard Rules",
      changeType: "add",
      proposedChange: "Always validate cache keys before using.",
      reason: "FTS5 corruption guard test",
    },
    {
      sourcePath: `vault/studio/memory/${PREPOP_AGENT}/staged/fake-20260407-000002-bench.md`,
      title: "Bench prepop proposal 2",
      section: "Postmortem Reflexes",
      changeType: "add",
      proposedChange: "Run --rebuild after any migration that drops an FTS5 table.",
      reason: "FTS5 corruption guard test",
    },
    {
      sourcePath: `vault/studio/memory/${PREPOP_AGENT}/staged/fake-20260407-000003-bench.md`,
      title: "Bench prepop proposal 3",
      section: "Core Opinions",
      changeType: "modify",
      proposedChange: "Hash-based invalidation beats TTL for deterministic pipelines.",
      reason: "FTS5 corruption guard test",
    },
  ];

  console.log(`[bench] inserting ${fakeRows.length} synthetic staged_proposals rows...`);

  for (const row of fakeRows) {
    raw.exec(`
      INSERT OR IGNORE INTO staged_proposals
        (agent, title, section, change_type, proposed_change, reason,
         status, source_path, file_hash, created_at, updated_at)
      VALUES
        ('${PREPOP_AGENT}', '${row.title.replace(/'/g, "''")}',
         '${row.section}', '${row.changeType}',
         '${row.proposedChange.replace(/'/g, "''")}',
         '${row.reason.replace(/'/g, "''")}',
         'pending', '${row.sourcePath}', 'bench-fake-hash', '${now}', '${now}')
    `);
  }

  const insertCount = (
    raw.prepare(
      `SELECT COUNT(*) as c FROM staged_proposals WHERE agent = '${PREPOP_AGENT}'`
    ).get() as { c: number }
  ).c;
  console.log(`[bench] inserted ${insertCount} rows for agent '${PREPOP_AGENT}'`);

  console.log(`[bench] running syncStaged (orphan removal path)...`);
  const changed = await syncStaged();
  console.log(`[bench] syncStaged changed=${changed}`);

  const afterCount = (
    raw.prepare(
      `SELECT COUNT(*) as c FROM staged_proposals WHERE agent = '${PREPOP_AGENT}'`
    ).get() as { c: number }
  ).c;

  if (afterCount !== 0) {
    throw new Error(
      `Expected 0 staged_proposals for '${PREPOP_AGENT}' after orphan removal, got ${afterCount}`
    );
  }

  console.log(`[bench] Scenario 1: PASS (orphan removal worked, no FTS5 errors)`);
  prepopPassed = true;
} catch (err: any) {
  prepopError = err.message ?? String(err);
  console.error(`[bench] Scenario 1: FAIL — ${prepopError}`);
} finally {
  try {
    const raw = getRawDb();
    raw.exec(`DELETE FROM staged_proposals WHERE agent = '${PREPOP_AGENT}'`);
    raw.exec(`DELETE FROM sync_meta WHERE source_path LIKE '%${PREPOP_AGENT}%'`);
  } catch {
    // Non-fatal
  }
}

console.log("");

// ── Scenario 2: Cache benchmark (hermetic freeze/restore) ─────────────────────

console.log(`[bench] === Scenario 2: Cache benchmark ===`);
console.log(`[bench] target agent: ${TARGET_AGENT}`);

// Snapshot soul + staged dir BEFORE any pipeline run
const soulSnapshot = snapshotSoul(TARGET_AGENT);
if (soulSnapshot === null) {
  console.error(`[bench] FAIL: soul file not found for agent '${TARGET_AGENT}'`);
  process.exit(1);
}
const stagedSnapshot = snapshotStagedDir(TARGET_AGENT);
console.log(`[bench] soul snapshot: ${soulSnapshot.length} bytes`);
console.log(`[bench] staged snapshot: ${stagedSnapshot.size} pre-existing file(s)`);

// Clear the distill cache so cold run is a guaranteed miss
console.log(`[bench] clearing distill cache...`);
const cleared = clearDistillCache();
console.log(`[bench] cleared ${cleared} cache file(s)`);

let coldMs = 0;
let hotMs = 0;
let coldProposals = 0;
let hotProposals = 0;
let cacheHitConfirmed = false;
let cacheBenchPassed = false;
let cacheBenchError: string | null = null;

try {
  // ── Cold run ────────────────────────────────────────────────────────────────
  console.log(`[bench] cold run (cache miss expected)...`);
  const t1 = Date.now();
  const result1 = await autonomousDistill([TARGET_AGENT], { noCache: false });
  coldMs = Date.now() - t1;
  coldProposals = result1.summary.totalProposals;
  console.log(`[bench] cold: ${coldMs}ms (${coldProposals} proposals processed)`);

  // Verify cache was populated
  const cacheKey = buildCacheKey(TARGET_AGENT);
  // NOTE: buildCacheKey uses CURRENT soul bytes — soul may have been mutated by
  // auto-apply, so this key will NOT match the key that was written during cold
  // run. That's exactly the bug this benchmark exists to expose. We restore
  // first, then verify.

  // ── Restore after cold run ──────────────────────────────────────────────────
  console.log(`[bench] restoring soul file (undoing any auto-applies)...`);
  restoreSoul(TARGET_AGENT, soulSnapshot);

  // Clean staged files the cold run created
  const coldStagedDeleted = await cleanStagedDir(TARGET_AGENT, stagedSnapshot);
  console.log(`[bench] cleaned ${coldStagedDeleted} staged file(s) from cold run`);

  // Now verify the cache was populated with the correct (pre-mutation) key
  const restoredCacheKey = buildCacheKey(TARGET_AGENT);
  const cached = readDistillCache(TARGET_AGENT, restoredCacheKey);
  if (!cached) {
    console.warn(`[bench] WARNING: cache not populated after cold run`);
    console.warn(`[bench]   key after restore: ${restoredCacheKey}`);
    console.warn(`[bench]   Check vault/studio/usage/distill-cache/ — agent may have no knowledge files`);
  } else {
    console.log(`[bench] cache confirmed: key=${restoredCacheKey}`);
    cacheHitConfirmed = true;
  }

  // ── Hot run ─────────────────────────────────────────────────────────────────
  console.log(`[bench] hot run (cache hit expected)...`);
  const t2 = Date.now();
  const result2 = await autonomousDistill([TARGET_AGENT], { noCache: false });
  hotMs = Date.now() - t2;
  hotProposals = result2.summary.totalProposals;
  console.log(`[bench] hot:  ${hotMs}ms (${hotProposals} proposals processed)`);

  cacheBenchPassed = hotMs < TARGET_MS;
} catch (err: any) {
  cacheBenchError = err.message ?? String(err);
  console.error(`[bench] Scenario 2 error: ${cacheBenchError}`);
} finally {
  // CRITICAL: always restore soul + clean staged, even on failure
  try {
    restoreSoul(TARGET_AGENT, soulSnapshot);
    const finalStagedDeleted = await cleanStagedDir(TARGET_AGENT, stagedSnapshot);
    if (finalStagedDeleted > 0) {
      console.log(`[bench] finally: cleaned ${finalStagedDeleted} staged file(s) from hot run`);
    }
  } catch (cleanErr: any) {
    console.error(`[bench] CRITICAL: cleanup failed — soul file may be in inconsistent state`);
    console.error(`[bench]   ${cleanErr.message ?? cleanErr}`);
    // Still exit non-zero — operator needs to know
  }
}

// ── Results ───────────────────────────────────────────────────────────────────

console.log("");
console.log(`[bench] === Results ===`);
console.log(`[bench] Scenario 1 (pre-populated DB):  ${prepopPassed ? "PASS" : `FAIL — ${prepopError}`}`);
console.log(`[bench] cold run:                        ${coldMs}ms (${coldProposals} proposals)`);
console.log(`[bench] hot run:                         ${hotMs}ms (${hotProposals} proposals)`);
console.log(`[bench] target:                          < ${TARGET_MS}ms`);

if (hotMs > 0 && coldMs > 0) {
  const ratio = (coldMs / hotMs).toFixed(1);
  console.log(`[bench] speedup:                         ${ratio}x`);
}

if (!cacheHitConfirmed) {
  console.warn(`[bench] WARNING: cache hit not confirmed — speedup may not reflect real caching`);
}

if (cacheBenchError) {
  console.log(`[bench] Scenario 2 (cache benchmark):   FAIL — ${cacheBenchError}`);
} else {
  console.log(`[bench] Scenario 2 (cache benchmark):   ${cacheBenchPassed ? "PASS" : `FAIL (hot=${hotMs}ms >= ${TARGET_MS}ms)`}`);
}

// Verify soul file is clean (sanity check)
const finalSoulBytes = snapshotSoul(TARGET_AGENT);
if (finalSoulBytes && soulSnapshot) {
  const soulsMatch = Buffer.compare(finalSoulBytes, soulSnapshot) === 0;
  console.log(`[bench] soul file restored:              ${soulsMatch ? "YES (clean)" : "NO — MISMATCH (check manually)"}`);
  if (!soulsMatch) {
    console.error(`[bench] CRITICAL: soul file does not match pre-benchmark snapshot. Manual recovery needed.`);
  }
}

// Verify staged dir is clean
const finalStagedSnapshot = snapshotStagedDir(TARGET_AGENT);
const stagedResidueCount = [...finalStagedSnapshot].filter(p => !stagedSnapshot.has(p)).length;
if (stagedResidueCount > 0) {
  console.error(`[bench] WARNING: ${stagedResidueCount} staged file(s) left over after benchmark (cleanup failed)`);
} else {
  console.log(`[bench] staged dir clean:                YES (no residue)`);
}

let exitCode = 0;

if (!prepopPassed) {
  console.error(`[bench] FAIL: Scenario 1 failed — ${prepopError}`);
  exitCode = 1;
}

if (cacheBenchError) {
  console.error(`[bench] FAIL: Scenario 2 threw — ${cacheBenchError}`);
  exitCode = 1;
} else if (!cacheBenchPassed) {
  console.error(`[bench] FAIL: hot run took ${hotMs}ms, target was <${TARGET_MS}ms`);
  exitCode = 1;
}

if (exitCode === 0) {
  console.log(`[bench] ALL PASS`);
}

process.exit(exitCode);

