420	 * @returns Video metadata and download URL
421	 */
422	export async function generateVideo(config: VideoConfig): Promise<VideoResult> {
423	  const apiKey = getApiKey();
424	  const model = config.model ?? "MiniMax-Hailuo-2.3";
425	  const duration = config.duration ?? 6;
426	  const resolution = config.resolution ?? "1080P";
427	  const pollInterval = config.pollIntervalSec ?? 10;
428	
429	  // Step 1: Submit generation task
430	  const body: Record<string, any> = {
431	    model,
432	    prompt: config.prompt,
433	    duration,
434	    resolution,
435	  };
436	
437	  if (config.firstFrameImage) body.first_frame_image = config.firstFrameImage;
438	  if (config.lastFrameImage) body.last_frame_image = config.lastFrameImage;
439	  if (config.subjectReference) body.subject_reference = config.subjectReference;
440	
441	  const startTime = Date.now();
442	
443	  const createResp = await fetch(`${API_BASE}/video_generation`, {
444	    method: "POST",
445	    headers: {
446	      "Content-Type": "application/json",
447	      "Authorization": `Bearer ${apiKey}`,
448	    },
449	    body: JSON.stringify(body),
450	    signal: AbortSignal.timeout(30_000),
451	  });
452	
453	  if (!createResp.ok) {
454	    throw new Error(`MiniMax API error: HTTP ${createResp.status} ${createResp.statusText}`);
455	  }
456	
457	  const createJson = await createResp.json() as any;
458	
459	  if (createJson.base_resp?.status_code && createJson.base_resp.status_code !== 0) {
460	    const code = createJson.base_resp.status_code;
461	    const msg = ERROR_CODES[code] || createJson.base_resp.status_msg || `Error code ${code}`;
462	    throw new Error(`MiniMax error: ${msg}`);
463	  }
464	
465	  const taskId = createJson.task_id;
466	  if (!taskId) {
467	    throw new Error("No task_id returned from video generation");
468	  }
469	
470	  // Step 2: Poll for completion
471	  let fileId = "";
472	  let attempts = 0;
473	  const maxAttempts = Math.ceil(600 / pollInterval); // 10 min max
474	
475	  while (attempts < maxAttempts) {
476	    await sleep(pollInterval * 1000);
477	    attempts++;
478	
479	    const statusResp = await fetch(
480	      `${API_BASE}/query/video_generation?task_id=${taskId}`,
481	      {
482	        headers: { "Authorization": `Bearer ${apiKey}` },
483	        signal: AbortSignal.timeout(15_000),
484	      }
485	    );
486	
487	    const statusJson = await statusResp.json() as any;
488	    const status = statusJson.status;
489	
490	    if (status === "Success") {
491	      fileId = statusJson.file_id;
492	      break;
493	    } else if (status === "Fail") {
494	      throw new Error(`Video generation failed: ${statusJson.error_message || "unknown"}`);
495	    }
496	  }
497	
498	  if (!fileId) {
499	    throw new Error(`Video generation timed out after ${maxAttempts * pollInterval}s`);
500	  }
501	
502	  // Step 3: Retrieve download URL
503	  const retrieveResp = await fetch(
504	    `${API_BASE}/files/retrieve?file_id=${fileId}`,
505	    {
506	      headers: { "Authorization": `Bearer ${apiKey}` },
507	      signal: AbortSignal.timeout(15_000),
508	    }
509	  );
510	
511	  const retrieveJson = await retrieveResp.json() as any;
512	  const downloadUrl = retrieveJson.file?.download_url;
513	
514	  if (!downloadUrl) {
515	    throw new Error("No download_url in file retrieval response");
516	  }
517	
518	  const durationMs = Date.now() - startTime;
519	  const costUsd = estimateVideoCost(model, resolution, duration);
520	
521	  // Track usage
522	  try {
523	    trackUsage({
524	      provider: "minimax",
525	      model,
526	      caller: config.caller ?? "minimax-video",
527	      inputTokens: 0,
528	      outputTokens: 0,
529	      costUsd,
530	      durationMs,
531	    });
532	  } catch {}
533	
534	  return {
535	    taskId,
536	    fileId,
537	    downloadUrl,
538	    model,
539	    duration,
540	    resolution,
541	    costUsd,
542	    generationTimeSec: Math.round(durationMs / 1000),
543	  };
544	}
