/**
 * minimax.ts — MiniMax API client for freddie-ai
 *
 * Direct REST client for MiniMax APIs. No official SDK — uses fetch.
 * Supports music generation, text chat, image generation, and video generation.
 *
 * Requires MINIMAX_API_KEY in .env (Bun loads automatically).
 */

import { trackUsage } from "./ai-usage.js";

// ── Config ───────────────────────────────────────────────────────────────────

const API_BASE = "https://api.minimax.io/v1";

export type MusicModel = "music-2.5+" | "music-2.5";

export interface AudioSettings {
  sampleRate?: 16000 | 24000 | 32000 | 44100;
  bitrate?: 32000 | 64000 | 128000 | 256000;
  format?: "mp3" | "wav" | "pcm";
}

export interface MusicConfig {
  model?: MusicModel;
  prompt?: string;
  lyrics?: string;
  isInstrumental?: boolean;
  lyricsOptimizer?: boolean;
  audio?: AudioSettings;
  caller?: string;
}

const DEFAULT_AUDIO: Required<AudioSettings> = {
  sampleRate: 44100,
  bitrate: 256000,
  format: "mp3",
};

// ── Auth ─────────────────────────────────────────────────────────────────────

function getApiKey(): string {
  const key = process.env.MINIMAX_API_KEY;
  if (!key) {
    throw new Error(
      "MINIMAX_API_KEY not set. Add it to .env or set the environment variable.\n" +
      "Get your key at: https://platform.minimax.io"
    );
  }
  return key;
}

// ── Error Types ──────────────────────────────────────────────────────────────

const ERROR_CODES: Record<number, string> = {
  1002: "Rate limited — retry later",
  1004: "Authentication failed",
  1008: "Insufficient balance — top up at platform.minimax.io",
  1026: "Content flagged as sensitive",
  2013: "Invalid parameters",
  2049: "Invalid API key",
};

// ── Music Generation ─────────────────────────────────────────────────────────

export interface MusicResult {
  audioUrl?: string;
  audioHex?: string;
  duration: number;       // milliseconds
  sampleRate: number;
  channels: number;
  bitrate: number;
  sizeBytes: number;
  model: string;
  costUsd: number;
}

/**
 * Generate a music track via MiniMax API.
 *
 * @param config - Music generation configuration
 * @returns Generated audio metadata and URL/hex data
 */
export async function generateMusic(config: MusicConfig): Promise<MusicResult> {
  const apiKey = getApiKey();
  const model = config.model ?? "music-2.5+";
  const audio = { ...DEFAULT_AUDIO, ...config.audio };

  // Validate: need either prompt (instrumental) or lyrics
  if (!config.prompt && !config.lyrics) {
    throw new Error("Either prompt or lyrics (or both) must be provided");
  }

  if (config.isInstrumental && model !== "music-2.5+") {
    throw new Error("Instrumental mode requires music-2.5+ model");
  }

  const body: Record<string, any> = {
    model,
    output_format: "url",
    audio_setting: {
      sample_rate: audio.sampleRate,
      bitrate: audio.bitrate,
      format: audio.format,
    },
  };

  if (config.prompt) body.prompt = config.prompt;
  if (config.lyrics) body.lyrics = config.lyrics;
  if (config.isInstrumental) body.is_instrumental = true;
  if (config.lyricsOptimizer) body.lyrics_optimizer = true;

  const startTime = Date.now();

  const response = await fetch(`${API_BASE}/music_generation`, {
    method: "POST",
    headers: {
      "Content-Type": "application/json",
      "Authorization": `Bearer ${apiKey}`,
    },
    body: JSON.stringify(body),
    signal: AbortSignal.timeout(300_000), // 5 min — music generation takes 2-4 min
  });

  if (!response.ok) {
    throw new Error(`MiniMax API error: HTTP ${response.status} ${response.statusText}`);
  }

  const json = await response.json() as any;
  const durationMs = Date.now() - startTime;

  // Check for API-level errors
  if (json.base_resp?.status_code && json.base_resp.status_code !== 0) {
    const code = json.base_resp.status_code;
    const msg = ERROR_CODES[code] || json.base_resp.status_msg || `Error code ${code}`;
    throw new Error(`MiniMax error: ${msg}`);
  }

  // Check generation status
  if (json.data?.status === 1) {
    throw new Error("MiniMax generation still in progress — async polling not yet supported");
  }

  const extra = json.extra_info || {};
  const costUsd = model === "music-2.5+" || model === "music-2.5" ? 0.15 : 0.03;

  const result: MusicResult = {
    audioUrl: typeof json.data?.audio === "string" && json.data.audio.startsWith("http")
      ? json.data.audio
      : undefined,
    audioHex: typeof json.data?.audio === "string" && !json.data.audio.startsWith("http")
      ? json.data.audio
      : undefined,
    duration: extra.music_duration ?? 0,
    sampleRate: extra.music_sample_rate ?? audio.sampleRate!,
    channels: extra.music_channel ?? 2,
    bitrate: extra.bitrate ?? audio.bitrate!,
    sizeBytes: extra.music_size ?? 0,
    model,
    costUsd,
  };

  // Track usage
  try {
    trackUsage({
      provider: "minimax",
      model,
      caller: config.caller ?? "minimax-music",
      inputTokens: 0,
      outputTokens: 0,
      costUsd,
      durationMs,
    });
  } catch {
    // Usage tracking should never block
  }

  return result;
}

// ── Text Chat (placeholder for future use) ───────────────────────────────────

export interface ChatConfig {
  model?: "MiniMax-M2.7" | "MiniMax-M2.5";
  messages: Array<{ role: "system" | "user" | "assistant"; content: string }>;
  temperature?: number;
  maxTokens?: number;
  caller?: string;
}

export interface ChatResult {
  text: string;
  model: string;
  inputTokens: number;
  outputTokens: number;
  costUsd: number;
}

/**
 * Chat completion via MiniMax API.
 */
export async function chatCompletion(config: ChatConfig): Promise<ChatResult> {
  const apiKey = getApiKey();
  const model = config.model ?? "MiniMax-M2.7";

  const response = await fetch(`${API_BASE}/text/chatcompletion_v2`, {
    method: "POST",
    headers: {
      "Content-Type": "application/json",
      "Authorization": `Bearer ${apiKey}`,
    },
    body: JSON.stringify({
      model,
      messages: config.messages,
      temperature: config.temperature ?? 0.7,
      max_tokens: config.maxTokens ?? 4096,
    }),
  });

  if (!response.ok) {
    throw new Error(`MiniMax API error: HTTP ${response.status} ${response.statusText}`);
  }

  const json = await response.json() as any;

  if (json.base_resp?.status_code && json.base_resp.status_code !== 0) {
    const code = json.base_resp.status_code;
    const msg = ERROR_CODES[code] || json.base_resp.status_msg || `Error code ${code}`;
    throw new Error(`MiniMax error: ${msg}`);
  }

  const choice = json.choices?.[0];
  const text = choice?.message?.content ?? "";
  const usage = json.usage || {};
  const inputTokens = usage.prompt_tokens ?? 0;
  const outputTokens = usage.completion_tokens ?? 0;

  const costUsd = (inputTokens / 1_000_000) * 0.30 + (outputTokens / 1_000_000) * 1.20;

  // Track usage
  try {
    trackUsage({
      provider: "minimax",
      model,
      caller: config.caller ?? "minimax-chat",
      inputTokens,
      outputTokens,
      costUsd: Math.round(costUsd * 1_000_000) / 1_000_000,
    });
  } catch {}

  return {
    text,
    model,
    inputTokens,
    outputTokens,
    costUsd: Math.round(costUsd * 1_000_000) / 1_000_000,
  };
}

// ── Image Generation ──────────────────────────────────────────────────────

export type ImageModel = "image-01";
export type AspectRatio = "1:1" | "16:9" | "9:16" | "4:3" | "3:4";

export interface SubjectReference {
  type: string;
  image_file: string;
}

export interface ImageConfig {
  model?: ImageModel;
  prompt: string;
  aspectRatio?: AspectRatio;
  subjectReference?: SubjectReference[];
  caller?: string;
}

export interface ImageResult {
  images: string[];       // base64-encoded image data
  aspectRatio: AspectRatio;
  model: string;
  costUsd: number;
}

const COST_PER_IMAGE = 0.0035;

/**
 * Generate an image via MiniMax API.
 *
 * @param config - Image generation configuration
 * @returns Generated image(s) as base64 strings
 */
export async function generateImage(config: ImageConfig): Promise<ImageResult> {
  const apiKey = getApiKey();
  const model = config.model ?? "image-01";
  const aspectRatio = config.aspectRatio ?? "1:1";

  const body: Record<string, any> = {
    model,
    prompt: config.prompt,
    aspect_ratio: aspectRatio,
    response_format: "base64",
  };

  if (config.subjectReference) {
    body.subject_reference = config.subjectReference;
  }

  const startTime = Date.now();

  const response = await fetch(`${API_BASE}/image_generation`, {
    method: "POST",
    headers: {
      "Content-Type": "application/json",
      "Authorization": `Bearer ${apiKey}`,
    },
    body: JSON.stringify(body),
    signal: AbortSignal.timeout(60_000),
  });

  if (!response.ok) {
    throw new Error(`MiniMax API error: HTTP ${response.status} ${response.statusText}`);
  }

  const json = await response.json() as any;
  const durationMs = Date.now() - startTime;

  if (json.base_resp?.status_code && json.base_resp.status_code !== 0) {
    const code = json.base_resp.status_code;
    const msg = ERROR_CODES[code] || json.base_resp.status_msg || `Error code ${code}`;
    throw new Error(`MiniMax error: ${msg}`);
  }

  const images: string[] = json.data?.image_base64 || [];
  if (images.length === 0) {
    throw new Error("No image returned");
  }

  // Track usage
  try {
    trackUsage({
      provider: "minimax",
      model,
      caller: config.caller ?? "minimax-image",
      inputTokens: 0,
      outputTokens: 0,
      costUsd: COST_PER_IMAGE,
      durationMs,
    });
  } catch {}

  return {
    images,
    aspectRatio,
    model,
    costUsd: COST_PER_IMAGE,
  };
}

// ── Video Generation ──────────────────────────────────────────────────────

export type VideoModel = "MiniMax-Hailuo-2.3" | "MiniMax-Hailuo-2.3-Fast" | "MiniMax-Hailuo-02";
export type VideoResolution = "1080P" | "768P" | "512P";
export type VideoDuration = 6 | 10;

export interface VideoConfig {
  model?: VideoModel;
  prompt: string;
  duration?: VideoDuration;
  resolution?: VideoResolution;
  firstFrameImage?: string;
  lastFrameImage?: string;
  subjectReference?: Array<{ type: string; image: string[] }>;
  pollIntervalSec?: number;
  caller?: string;
}

export interface VideoResult {
  taskId: string;
  fileId: string;
  downloadUrl: string;
  model: string;
  duration: VideoDuration;
  resolution: VideoResolution;
  costUsd: number;
  generationTimeSec: number;
}

// Pricing per video (model → resolution → duration)
const VIDEO_PRICING: Record<string, Record<string, Record<number, number>>> = {
  "MiniMax-Hailuo-2.3": {
    "768P": { 6: 0.28, 10: 0.42 },
    "1080P": { 6: 0.37, 10: 0.56 },
  },
  "MiniMax-Hailuo-2.3-Fast": {
    "768P": { 6: 0.19, 10: 0.28 },
    "1080P": { 6: 0.22, 10: 0.33 },
  },
  "MiniMax-Hailuo-02": {
    "512P": { 6: 0.10, 10: 0.15 },
    "768P": { 6: 0.28, 10: 0.42 },
    "1080P": { 6: 0.37, 10: 0.56 },
  },
};

function estimateVideoCost(model: string, resolution: string, duration: number): number {
  return VIDEO_PRICING[model]?.[resolution]?.[duration] ?? 0.37;
}

function sleep(ms: number): Promise<void> {
  return new Promise(resolve => setTimeout(resolve, ms));
}

/**
 * Generate a video via MiniMax Hailuo API.
 * Async: submits task → polls for completion → returns download URL.
 *
 * @param config - Video generation configuration
 * @returns Video metadata and download URL
 */
export async function generateVideo(config: VideoConfig): Promise<VideoResult> {
  const apiKey = getApiKey();
  const model = config.model ?? "MiniMax-Hailuo-2.3";
  const duration = config.duration ?? 6;
  const resolution = config.resolution ?? "1080P";
  const pollInterval = config.pollIntervalSec ?? 10;

  // Step 1: Submit generation task
  const body: Record<string, any> = {
    model,
    prompt: config.prompt,
    duration,
    resolution,
  };

  if (config.firstFrameImage) body.first_frame_image = config.firstFrameImage;
  if (config.lastFrameImage) body.last_frame_image = config.lastFrameImage;
  if (config.subjectReference) body.subject_reference = config.subjectReference;

  const startTime = Date.now();

  const createResp = await fetch(`${API_BASE}/video_generation`, {
    method: "POST",
    headers: {
      "Content-Type": "application/json",
      "Authorization": `Bearer ${apiKey}`,
    },
    body: JSON.stringify(body),
    signal: AbortSignal.timeout(30_000),
  });

  if (!createResp.ok) {
    throw new Error(`MiniMax API error: HTTP ${createResp.status} ${createResp.statusText}`);
  }

  const createJson = await createResp.json() as any;

  if (createJson.base_resp?.status_code && createJson.base_resp.status_code !== 0) {
    const code = createJson.base_resp.status_code;
    const msg = ERROR_CODES[code] || createJson.base_resp.status_msg || `Error code ${code}`;
    throw new Error(`MiniMax error: ${msg}`);
  }

  const taskId = createJson.task_id;
  if (!taskId) {
    throw new Error("No task_id returned from video generation");
  }

  // Step 2: Poll for completion
  let fileId = "";
  let attempts = 0;
  const maxAttempts = Math.ceil(600 / pollInterval); // 10 min max

  while (attempts < maxAttempts) {
    await sleep(pollInterval * 1000);
    attempts++;

    const statusResp = await fetch(
      `${API_BASE}/query/video_generation?task_id=${taskId}`,
      {
        headers: { "Authorization": `Bearer ${apiKey}` },
        signal: AbortSignal.timeout(15_000),
      }
    );

    const statusJson = await statusResp.json() as any;
    const status = statusJson.status;

    if (status === "Success") {
      fileId = statusJson.file_id;
      break;
    } else if (status === "Fail") {
      throw new Error(`Video generation failed: ${statusJson.error_message || "unknown"}`);
    }
  }

  if (!fileId) {
    throw new Error(`Video generation timed out after ${maxAttempts * pollInterval}s`);
  }

  // Step 3: Retrieve download URL
  const retrieveResp = await fetch(
    `${API_BASE}/files/retrieve?file_id=${fileId}`,
    {
      headers: { "Authorization": `Bearer ${apiKey}` },
      signal: AbortSignal.timeout(15_000),
    }
  );

  const retrieveJson = await retrieveResp.json() as any;
  const downloadUrl = retrieveJson.file?.download_url;

  if (!downloadUrl) {
    throw new Error("No download_url in file retrieval response");
  }

  const durationMs = Date.now() - startTime;
  const costUsd = estimateVideoCost(model, resolution, duration);

  // Track usage
  try {
    trackUsage({
      provider: "minimax",
      model,
      caller: config.caller ?? "minimax-video",
      inputTokens: 0,
      outputTokens: 0,
      costUsd,
      durationMs,
    });
  } catch {}

  return {
    taskId,
    fileId,
    downloadUrl,
    model,
    duration,
    resolution,
    costUsd,
    generationTimeSec: Math.round(durationMs / 1000),
  };
}

