#!/usr/bin/env bun
/**
 * minimax-debug.ts — Reproduce the MiniMax judge parser failure.
 *
 * Sends a realistic judge prompt to MiniMax-M2.5 and logs the raw response
 * bytes BEFORE any JSON parsing. This isolates whether the failure is:
 *   - HTTP error (4xx/5xx + HTML body)
 *   - Invalid JSON response
 *   - Valid JSON but unexpected shape
 *   - Empty body / truncation
 *   - Reasoning token contamination
 */

// Build a realistic judge prompt — same shape as buildJudgePrompt in judge-panel.ts
const JUDGE_PROMPT = `You are a judge reviewing a proposed change to an AI agent's soul file (core identity document).

## Agent: echo

## Current Soul File
# Echo — Session engineer listening from the control room

## Who I Am
Started as a studio intern patching cables and aligning tape heads.

## How I Think
- Listens to the whole arrangement before commenting on any single part
- Assigns confidence levels: high, medium, low

## Proposed Change
Type: modify
Section: How I Think
Confidence: high
Evidence: gemini-suno-critique-filter-rules.md

Content to apply:
- For Suno, Gemini's structural observations (frequency collisions, missing tags, redundancy, tag counts) are high-confidence. Its per-instrument mixing, production effects, wholesale rewrites, or atmospheric stripping suggestions are low-confidence and often contradict Suno's behavior; I mine individual fixes from these rather than applying them wholesale.

## Evidence (from knowledge files)
gemini-suno-critique-filter-rules.md

## Validation Gate Results
All structural gates passed:
- safety: PASS — No changes target protected sections
- size: PASS — 1 lines added/modified, 0 removed — within limits
- drift: PASS — 30-day drift 3/5 (46-line soul, 10% threshold)
- regression: PASS — 1 high-similarity pair(s) checked, no contradictions
- constitution: PASS — PASS

## Your Task

Evaluate whether this soul file change should be automatically applied. Consider:

1. Evidence quality
2. Non-contradiction
3. Utility
4. Proportionality

## Response Format

Respond with EXACTLY one line in this format:
APPROVE: {brief reason why this change is safe and beneficial}
or
REJECT: {brief reason why this change should not be auto-applied}

Do not include any other text.`;

const API_KEY = process.env.MINIMAX_API_KEY;
if (!API_KEY) {
  console.error("MINIMAX_API_KEY not set");
  process.exit(1);
}

// Try both model names
const MODELS = ["MiniMax-M2.5", "MiniMax-M2.7"];

for (const model of MODELS) {
  console.log(`\n========== ${model} ==========`);

  const body = {
    model,
    messages: [{ role: "user", content: JUDGE_PROMPT }],
    temperature: 0.2,
    max_tokens: 1024,
  };

  const startTime = Date.now();

  try {
    const response = await fetch("https://api.minimax.io/v1/text/chatcompletion_v2", {
      method: "POST",
      headers: {
        "Content-Type": "application/json",
        "Authorization": `Bearer ${API_KEY}`,
      },
      body: JSON.stringify(body),
      signal: AbortSignal.timeout(60_000),
    });

    const durationMs = Date.now() - startTime;
    console.log(`HTTP status: ${response.status} ${response.statusText}`);
    console.log(`Duration:    ${durationMs}ms`);
    console.log(`Headers:`);
    for (const [k, v] of response.headers.entries()) {
      console.log(`  ${k}: ${v}`);
    }

    // Read raw bytes BEFORE parsing
    const rawText = await response.text();
    console.log(`\nRaw body length: ${rawText.length} bytes`);
    console.log(`Raw body first 1000 chars:`);
    console.log("---");
    console.log(rawText.slice(0, 1000));
    console.log("---");

    // Try parsing as JSON
    try {
      const json = JSON.parse(rawText);
      console.log(`\n✓ JSON parsed successfully`);
      console.log(`Keys at top level: ${Object.keys(json).join(", ")}`);
      if (json.base_resp) {
        console.log(`base_resp.status_code: ${json.base_resp.status_code}`);
        console.log(`base_resp.status_msg:  ${json.base_resp.status_msg}`);
      }
      if (json.choices) {
        console.log(`choices: ${json.choices.length}`);
        if (json.choices[0]) {
          const choice = json.choices[0];
          console.log(`choices[0].finish_reason: ${choice.finish_reason}`);
          console.log(`choices[0].message.role:  ${choice.message?.role}`);
          const content = choice.message?.content;
          console.log(`choices[0].message.content:`);
          console.log("---");
          console.log(content);
          console.log("---");
          console.log(`Content length: ${content?.length ?? 0}`);
        }
      }
      if (json.usage) {
        console.log(`usage: ${JSON.stringify(json.usage)}`);
      }
    } catch (parseErr: any) {
      console.log(`\n✗ JSON parse FAILED: ${parseErr.message}`);
      console.log(`This is the bug — raw body is not valid JSON.`);
    }
  } catch (err: any) {
    console.log(`✗ Request failed: ${err.message}`);
    console.log(`Error type: ${err.constructor.name}`);
    if (err.cause) {
      console.log(`Cause: ${err.cause}`);
    }
  }
}

